package com.campus.health.common;public class ApiResponse<T>{public int code;public String message;public T data;public ApiResponse(int code,String message,T data){this.code=code;this.message=message;this.data=data;}public static<T> ApiResponse<T> ok(T data){return new ApiResponse<>(0,"success",data);}public static<T> ApiResponse<T> fail(String message){return new ApiResponse<>(1,message,null);}}